import React from 'react';

const CardDescriptionSlider = () => {
  return (
    <>
    <div className="TVHotelDescriptionText">
              Городской отель в районе Фатих/ Беязит. Небольшие по площади
              номера, бесплатный Wi-Fi. Предлагаются завтраки по утрам. Подойдет
              для бюджетной поездки в Стамбул.
    </div>
      <div className="TVHotelDescriptionSlider">
              <div className="TVHotelGalleryControl">
                <div className="TVHotelGallerySlider">
                  <div className="TVPhotoSlider">
                    <div className="TVPhotoSliderList">
                      <div
                        className="TVPhotoSliderItem TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610201.jpg")',
                        }}
                      />
                      <div
                        className="TVPhotoSliderItem TVHide TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610203.jpg")',
                        }}
                      />
                      <div
                        className="TVPhotoSliderItem TVHide TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610207.jpg")',
                        }}
                      />
                      <div
                        className="TVPhotoSliderItem TVHide TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610208.jpg")',
                        }}
                      />
                      <div
                        className="TVPhotoSliderItem TVHide TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610209.jpg")',
                        }}
                      />
                      <div
                        className="TVPhotoSliderItem TVHide TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610210.jpg")',
                        }}
                      />
                      <div
                        className="TVPhotoSliderItem TVHide TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610211.jpg")',
                        }}
                      />
                      <div
                        className="TVPhotoSliderItem TVHide TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610212.jpg")',
                        }}
                      />
                      <div
                        className="TVPhotoSliderItem TVHide TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610213.jpg")',
                        }}
                      />
                      <div
                        className="TVPhotoSliderItem TVHide TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610214.jpg")',
                        }}
                      />
                      <div
                        className="TVPhotoSliderItem TVHide TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610215.jpg")',
                        }}
                      />
                      <div
                        className="TVPhotoSliderItem TVHide TVBackgroundSize-Cover"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610216.jpg")',
                        }}
                      />
                    </div>
                    <div className="TVSNavLeft TVHide" />
                    <div className="TVSNavRight" />
                    <div className="TVPhotoSliderCounter">1/24</div>
                  </div>
                </div>
                <div className="TVHotelGalleryRightBlock">
                  <div className="TVHotelRatingBlock TVHide">
                    <div className="TVHotelRatingBox" />
                    <div className="TVHotelScoreBox">
                      <div className="TVHotelRatingText">
                        <a className="TVHotelRatingReviews">2</a>
                      </div>
                    </div>
                  </div>
                  <div className="TVHotelGalleryPreview">
                    <div className="TVPreviewGalleryControl">
                      <div
                        className="TVPreviewGalleryItem TVSelected"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610201.jpg")',
                        }}
                      />
                      <div
                        className="TVPreviewGalleryItem"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610203.jpg")',
                        }}
                      />
                      <div
                        className="TVPreviewGalleryItem"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610207.jpg")',
                        }}
                      />
                      <div
                        className="TVPreviewGalleryItem"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610208.jpg")',
                        }}
                      />
                      <div
                        className="TVPreviewGalleryItem"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610209.jpg")',
                        }}
                      />
                      <div
                        className="TVPreviewGalleryItem"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610210.jpg")',
                        }}
                      />
                      <div
                        className="TVPreviewGalleryItem"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610211.jpg")',
                        }}
                      />
                      <div
                        className="TVPreviewGalleryItem"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610212.jpg")',
                        }}
                      />
                      <div
                        className="TVPreviewGalleryItem"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610213.jpg")',
                        }}
                      />
                      <div
                        className="TVPreviewGalleryItem"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610214.jpg")',
                        }}
                      />
                      <div
                        className="TVPreviewGalleryItem"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610215.jpg")',
                        }}
                      />
                      <div
                        className="TVPreviewGalleryItem"
                        style={{
                          backgroundImage:
                            'url("//static.tourvisor.ru/hotel_pics/verybig/4/17444-1610216.jpg")',
                        }}
                      />
                    </div>
                  </div>
                  <div className="TVHotelGalleryMorePhotoBtn" />
                </div>
              </div>
            </div>
    </>
  );
};

export default CardDescriptionSlider;
